-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH current_equipment AS (
    SELECT
        DIM_EQUIPMENT_ID,
        EQPUN_NBR,
        MARK_CD,
        STATUS_CD,
        EDW_CURRENT_FLG
    FROM {{ ref('stg_dim_equipment') }}
    WHERE EDW_CURRENT_FLG = 'Y'
),

aar_base_lookup AS (
    SELECT
        EQPMNT_ID,
        EQPUN_NBR,
        MARK_CD
    FROM {{ ref('stg_eqpmnt_aar_base') }}
),

equipment_with_lookup AS (
    SELECT
        e.DIM_EQUIPMENT_ID,
        e.EQPUN_NBR,
        e.MARK_CD,
        e.STATUS_CD,
        a.EQPMNT_ID
    FROM current_equipment e
    LEFT JOIN aar_base_lookup a
        ON e.EQPUN_NBR = a.EQPUN_NBR
        AND e.MARK_CD = a.MARK_CD
),

filtered_for_soft_delete AS (
    SELECT *
    FROM equipment_with_lookup
    WHERE EQPMNT_ID IS NULL
       OR STATUS_CD = 'I'
)

SELECT
    DIM_EQUIPMENT_ID,
    '{{ var("repository_user_name", "dbt_user") }}' AS EDW_UPDATE_USER,
    CURRENT_TIMESTAMP() AS EDW_UPDATE_TMS,
    DATEADD('SECOND', 3661, DATE_TRUNC('DAY', CURRENT_TIMESTAMP())) AS EDW_END_EFCTV_DT,
    'N' AS EDW_CURRENT_FLG
FROM filtered_for_soft_delete
